package main

import (
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	// Compile the condition script once to avoid re-parsing for every item
	tempVM := otto.New()
	compiledScript, err := tempVM.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile condition script: %w", err)
	}

	for _, item := range items {
		// Create a new VM for each item to ensure isolation between script executions
		vm := otto.New()

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Run the pre-compiled condition script
		value, err := vm.Run(compiledScript)
		if err != nil {
			return nil, fmt.Errorf("failed to execute condition script: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

func main() {
	// Example usage
	items := []map[string]interface{}{
		{"id": 1, "active": true, "name": "Alice"},
		{"id": 2, "active": false, "name": "Bob"},
		{"id": 3, "active": true, "name": "Charlie"},
	}

	// Filter items where active is true
	filtered, err := FilterItems("item.active === true", items)
	if err != nil {
		fmt.Printf("Error filtering items: %v\n", err)
		return
	}

	fmt.Println("Filtered items:")
	for _, item := range filtered {
		fmt.Printf("%v\n", item)
	}
}

