import (
	"time"

	"github.com/robertkrimen/otto"
)

func deepCopy(src interface{}) interface{} {
	switch v := src.(type) {
	case map[string]interface{}:
		cp := make(map[string]interface{}, len(v))
		for key, value := range v {
			cp[key] = deepCopy(value)
		}
		return cp
	case []interface{}:
		cp := make([]interface{}, len(v))
		for i, value := range v {
			cp[i] = deepCopy(value)
		}
		return cp
	default:
		return v
	}
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	const scriptTimeout = 1 * time.Second

	for _, item := range items {
		// Create a deep copy of the item to prevent modifications to the original data
		itemCopy := deepCopy(item).(map[string]interface{})

		vm := otto.New()

		// Set up interrupt mechanism for script timeout
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		// Start timeout timer
		timer := time.AfterFunc(scriptTimeout, func() {
			interrupt <- nil
		})

		// Inject the copied item as a global variable named 'item'
		err := vm.Set("item", itemCopy)
		if err != nil {
			timer.Stop()
			return nil, err
		}

		// Run the condition script
		value, err := vm.Run(conditionScript)
		timer.Stop() // Ensure timer is stopped to prevent unnecessary interrupts
		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

