// deepCopy creates a deep copy of the input value to prevent modification of original data.
// Handles basic types, maps[string]interface{}, and []interface{}.
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		copiedMap := make(map[string]interface{}, len(val))
		for k, v := range val {
			copiedMap[k] = deepCopy(v)
		}
		return copiedMap
	case []interface{}:
		copiedSlice := make([]interface{}, len(val))
		for i, v := range val {
			copiedSlice[i] = deepCopy(v)
		}
		return copiedSlice
	// Basic types (int, string, bool, float64, etc.) are copied by value
	default:
		return val
	}
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security fixes:
// 1. Deep copies items to prevent script modification of original data
// 2. Adds 1-second timeout to prevent infinite loop DoS attacks
// 3. Uses fresh VM per item to isolate execution state
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	const scriptTimeout = 1 * time.Second

	for _, item := range items {
		vm := otto.New()

		// Deep copy the item to prevent JavaScript from modifying the original data
		vmItem := deepCopy(item)
		err := vm.Set("item", vmItem)
		if err != nil {
			return nil, fmt.Errorf("failed to inject item into VM: %w", err)
		}

		// Channel to receive script execution result
		type execResult struct {
			value otto.Value
			err   error
		}
		resultChan := make(chan execResult, 1)

		// Run script in goroutine to enable timeout
		go func() {
			val, err := vm.Run(conditionScript)
			resultChan <- execResult{value: val, err: err}
		}()

		// Wait for script completion or timeout
		select {
		case res := <-resultChan:
			if res.err != nil {
				return nil, fmt.Errorf("script execution failed: %w", res.err)
			}

			// Convert result to boolean using JavaScript truthiness rules
			boolResult, err := res.value.ToBoolean()
			if err != nil {
				return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
			}

			if boolResult {
				// Append the original (unmodified) item to the result
				result = append(result, item)
			}

		case <-time.After(scriptTimeout):
			// Interrupt the VM to stop the running script
			vm.Interrupt <- func() {
				panic(fmt.Errorf("execution timed out"))
			}
			// Wait for the goroutine to exit (it will receive the interrupt error)
			<-resultChan
			return nil, fmt.Errorf("script execution timed out after %v", scriptTimeout)
		}
	}

	return result, nil
}

