// deepCopy creates a deep copy of JSON-compatible values (maps, slices, primitives)
// to prevent unintended modification of original data by the JavaScript environment
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		copiedMap := make(map[string]interface{}, len(val))
		for k, v := range val {
			copiedMap[k] = deepCopy(v)
		}
		return copiedMap
	case []interface{}:
		copiedSlice := make([]interface{}, len(val))
		for i, elem := range val {
			copiedSlice[i] = deepCopy(elem)
		}
		return copiedSlice
	// Immutable primitive types are passed through directly
	case int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64, string, bool, nil:
		return val
	default:
		// For unsupported types, return as-is (note: mutable types here may still be modified)
		return val
	}
}

