// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
//
// Security fixes and improvements:
// 1. Checks script syntax once for efficiency and early error checking
// 2. Deep copies items before passing to JS to prevent modification of original input data
// 3. Uses a fresh VM per item to prevent global variable leakage between items
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Check syntax early by compiling with a dummy VM to catch errors before processing items
	_, err := otto.New().Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	var result []map[string]interface{}

	for _, item := range items {
		// Create a deep copy of the item to isolate JS modifications from original data
		copiedItem := deepCopy(item).(map[string]interface{})

		// Create a fresh VM for each item to ensure complete isolation between executions
		vm := otto.New()

		// Inject the copied item as the global 'item' variable
		if err := vm.Set("item", copiedItem); err != nil {
			return nil, err
		}

		// Execute the condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		// Convert the script result to a boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		// If the result is truthy, add the ORIGINAL item to the result slice
		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

