		if err := vm.Set("Function", otto.UndefinedValue()); err != nil {
			return nil, err
		}

		// Inject the current item as the global 'item' variable
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Execute the pre-compiled condition script
		value, err := vm.Run(script)
		if err != nil {
			return nil, err
		}

		// Convert the result to a boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

