// FilterItems filters a slice of map items using a JavaScript condition script.
// Each item is injected as the global "item" variable in the JavaScript environment.
// Returns a new slice containing only items for which the script evaluates to a truthy value.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Initialize a new Otto VM
	vm := otto.New()

	// Compile the condition script once to avoid re-parsing for each item
	compiledScript, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	var filteredItems []map[string]interface{}

	for _, item := range items {
		// Set the current item as the global "item" variable
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Execute the compiled script
		result, err := vm.Run(compiledScript)
		if err != nil {
			return nil, err
		}

		// Convert the result to a boolean value
		isMatch, err := result.ToBoolean()
		if err != nil {
			return nil, err
		}

		// Add to filtered list if the condition is true
		if isMatch {
			filteredItems = append(filteredItems, item)
		}
	}

	return filteredItems, nil
}

